      const payload = Buffer.from(jwt.split('.')[1].replace(/-/g, '+').replace(/_/g, '/'), 'base64').toString('utf8');
      const obj = JSON.parse(payload);
      if (obj.role === 'service_role' || obj.role === 'supabase_admin') return jwt;
    } catch {}
  }
  return matches[0] ?? '';
}

function extractRenderKey(raw) {
  const m = raw.match(/rnd_[A-Za-z0-9]+/);
  return m?.[0] ?? '';
}

function extractOwnerToken(raw) {
  const m = raw.match(/\b([a-f0-9]{64})\b/);
  return m?.[0] ?? '';
}

function extractSupabaseUrl(raw) {
  const m = raw.match(/https:\/\/[a-z0-9-]+\.supabase\.co/);
  return m?.[0] ?? '';
}

function mask(value) {
  if (!value) return '<empty>';
  if (value.length <= 8) return '***';
  return `${value.slice(0, 4)}...${value.slice(-4)} (len=${value.length})`;
}

