log(`  IVX_OWNER_PASSWORD ${mask(IVX_OWNER_PASSWORD)}`);
log(`  IVX_OWNER_TOKEN ${mask(IVX_OWNER_TOKEN)}`);
log(`  EXPO_PUBLIC_SUPABASE_URL ${EXPO_PUBLIC_SUPABASE_URL}`);
log(`  SUPABASE_SERVICE_ROLE_KEY ${mask(SUPABASE_SERVICE_ROLE_KEY)}`);
log(`  EXPO_PUBLIC_SUPABASE_ANON_KEY ${mask(EXPO_PUBLIC_SUPABASE_ANON_KEY)}`);

if (!RENDER_API_KEY || !IVX_OWNER_PASSWORD || !IVX_OWNER_TOKEN) {
  throw new Error('Missing one or more required credentials.');
}

// List Render services and pick the one for api.ivxholding.com
const services = await http(`${RENDER_API_BASE}/services?limit=20`, { headers: { Authorization: `Bearer ${RENDER_API_KEY}`, Accept: 'application/json' } });
log(`Render services list status: ${services.status}`);
if (!services.ok || !Array.isArray(services.body)) throw new Error('Could not list Render services.');

let serviceId = '';
let serviceName = '';
for (const item of services.body) {
  const svc = item?.service ?? item;
  const name = svc?.name ?? '';
  const id = svc?.id ?? '';
  const domains = Array.isArray(svc?.serviceDetails?.domainNames) ? svc.serviceDetails.domainNames : [];
  if (domains.includes('api.ivxholding.com') || name === 'ivx-holdings-platform' || name === 'ivx-owner-ai-backend') {
    serviceId = id;
    serviceName = name;
    log(`Selected Render service: ${serviceName} (${serviceId}) domains=${domains.join(',') || 'none'}`);
