  const r = await http(`${RENDER_API_BASE}/services/${encodeURIComponent(serviceId)}/env-vars/${encodeURIComponent(key)}`, {
    method: 'PUT',
    headers: { Authorization: `Bearer ${RENDER_API_KEY}`, 'Content-Type': 'application/json', Accept: 'application/json' },
    body: JSON.stringify({ value }),
  });
  log(`Render env var ${key}: ${r.status} ${r.ok ? 'ok' : 'failed'}`);
