const deploy = await http(`${RENDER_API_BASE}/services/${encodeURIComponent(serviceId)}/deploys`, {
  method: 'POST',
  headers: { Authorization: `Bearer ${RENDER_API_KEY}`, 'Content-Type': 'application/json', Accept: 'application/json' },
  body: JSON.stringify({ clearCache: 'clear' }),
});
log(`Render deploy trigger status: ${deploy.status}`);
if (!deploy.ok) throw new Error('Render deploy trigger failed.');
const deployId = deploy.body?.id ?? deploy.body?.deploy?.id ?? 'unknown';
log(`Render deploy id: ${deployId}`);

// Poll health/version until commit matches local HEAD
const localHead = execSync('git rev-parse HEAD').toString().trim();
log(`Local HEAD: ${localHead}`);
let matched = false;
for (let i = 0; i < 24; i++) {
