  try {
    const version = await http(`${LIVE_API}/version`);
    const liveCommit = version.body?.commit ?? '';
    log(`Poll ${i + 1}: live commit ${liveCommit}`);
    if (liveCommit === localHead) {
      matched = true;
      break;
    }
  } catch (e) {
    log(`Poll ${i + 1}: error ${e.message}`);
  }
}
if (!matched) throw new Error('Live version did not match local HEAD within 6 minutes.');

// Test owner login
const login = await http(`${LIVE_API}/api/ivx/owner-passwordless-login`, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({ email: OWNER_EMAIL }),
