// Test owner-variables/status with IVX_OWNER_TOKEN
const status = await http(`${LIVE_API}/api/ivx/owner-variables/status`, {
  headers: { Authorization: `Bearer ${IVX_OWNER_TOKEN}` },
});
log(`Owner variables status: ${status.status} ok=${status.ok}`);
if (!status.ok) throw new Error(`Owner variables status failed: ${JSON.stringify(status.body)}`);

log('ALL CHECKS PASSED');
